import React, { useState, useEffect, useRef, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { format } from 'date-fns';
import {
  exportBrainFile,
  importBrainFile,
  validateBrainFile,
  formatFileSize,
  isFileSystemAccessSupported,
  requestAutoSaveDirectory,
  autoSave,
} from '../services/brainBackup';
import {
  loadPreferences,
  savePreferences,
  getBackupHistory,
  shouldShowBackupReminder,
  getTimeSinceLastBackup,
  addHistoryEntry,
  type BackupPreferences,
  type BackupHistoryEntry,
} from '../services/backupPreferences';
import { indexedDBService } from '../services/indexedDB';
import { autoSaveManager } from '../services/autoSave';
import { exportToICS, importFromICS, downloadICS, readICSFile } from '../services/icsImportExport';
import { useCalendarStore } from '../stores/useCalendarStore';
import { useTerminalStore } from '../stores/useTerminalStore';
import { BackupSettings } from '../components/BackupSettings';

/**
 * Settings Page - Local-First Privacy
 * Comprehensive backup management with compression, auto-save, and history
 * 100% local storage - no cloud dependencies
 */
export const Settings: React.FC = () => {
  // State management
  const [isExporting, setIsExporting] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error' | 'info' | 'warning'; text: string } | null>(null);

  // Preferences
  const [preferences, setPreferences] = useState<BackupPreferences | null>(null);
  const [backupHistory, setBackupHistory] = useState<BackupHistoryEntry[]>([]);
  const [timeSinceLastBackup, setTimeSinceLastBackup] = useState<string | null>(null);
  const [backupReminder, setBackupReminder] = useState<any>(null);

  // Auto-save
  const [autoSaveDirectory, setAutoSaveDirectory] = useState<FileSystemDirectoryHandle | null>(null);

  // Advanced Details
  const [showAdvancedDetails, setShowAdvancedDetails] = useState(false);
  const [storageInfo, setStorageInfo] = useState<any>(null);

  // Auto-save visual feedback
  const [recentlySaved, setRecentlySaved] = useState<'compression' | 'reminder' | 'autoSave' | null>(null);

  // New Browser Warning
  const [showNewBrowserWarning, setShowNewBrowserWarning] = useState(false);
  const [hasData, setHasData] = useState(true);

  // Auto-Save customization
  const [customFilename, setCustomFilename] = useState('');
  const [versionCount, setVersionCount] = useState(7);

  // Calendar Import/Export
  const [isExportingCalendar, setIsExportingCalendar] = useState(false);
  const [isImportingCalendar, setIsImportingCalendar] = useState(false);
  const { events, addEvent } = useCalendarStore();

  // AI Terminal (legacy - now using multi-provider system)
  const { apiKey, model: _model, setApiKey: _setApiKey, setModel: _setModel } = useTerminalStore();
  const [_tempApiKey, _setTempApiKey] = useState('');
  const [_showApiKey, _setShowApiKey] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const icsFileInputRef = useRef<HTMLInputElement>(null);

  const loadAllData = useCallback(async () => {
    // Load preferences
    const prefs = await loadPreferences();
    setPreferences(prefs);

    // Initialize auto-save customization state (strip .brain extension for display)
    const filename = prefs.customFilename || 'Neuman.Brain';
    const nameWithoutExt = filename.replace(/\.brain$/i, '');
    setCustomFilename(nameWithoutExt);
    setVersionCount(prefs.versionCount || 7);

    // Load backup history
    const history = await getBackupHistory();
    setBackupHistory(history);

    // Get time since last backup
    const timeSince = await getTimeSinceLastBackup();
    setTimeSinceLastBackup(timeSince);

    // Check backup reminder
    const reminder = await shouldShowBackupReminder();
    setBackupReminder(reminder);

    // Load storage quota info
    try {
      const quota = await indexedDBService.getQuota();
      setStorageInfo(quota);

      // Check if this is a new browser (no data in IndexedDB)
      const keys = await indexedDBService.getAllKeys();
      const hasAnyData = keys.length > 0;
      setHasData(hasAnyData);

      // Show new browser warning if no data AND not dismissed
      const dismissed = localStorage.getItem('new-browser-warning-dismissed');
      if (!hasAnyData && !dismissed) {
        setShowNewBrowserWarning(true);
      }
    } catch (error) {
      console.error('Failed to load storage info:', error);
    }
  }, []);

  // Load data on mount
  useEffect(() => {
    document.title = 'Settings - Neuman Brain';
    loadAllData();
    // Initialize temp API key from store (legacy - now using ProviderSettings)
    // if (apiKey) {
    //   setTempApiKey(apiKey);
    // }
  }, [loadAllData, apiKey]);

  // Scroll to hash anchor on mount (for #account navigation)
  useEffect(() => {
    const hash = window.location.hash;
    if (hash) {
      // Small delay to ensure DOM is ready
      setTimeout(() => {
        const element = document.querySelector(hash);
        if (element) {
          element.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
      }, 100);
    }
  }, []);

  // Export handlers
  const handleExport = async (compressed: boolean = true) => {
    try {
      setIsExporting(true);
      setMessage(null);

      const result = await exportBrainFile({ compressed, prettyPrint: !compressed });

      // Add to history
      await addHistoryEntry({
        filename: result.filename,
        size: result.size,
        compressed: result.compressed,
        type: 'manual',
        status: 'success',
      });

      await loadAllData(); // Refresh

      const sizeInfo = formatFileSize(result.size);
      const compressionNote = compressed ? ' (compressed)' : '';
      setMessage({
        type: 'success',
        text: `Brain data exported successfully! File size: ${sizeInfo}${compressionNote}`
      });
    } catch (error) {
      setMessage({ type: 'error', text: `Export failed: ${error}` });
    } finally {
      setIsExporting(false);
    }
  };

  // Import handler
  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    try {
      setIsImporting(true);
      setMessage(null);

      // Validate file
      const validation = await validateBrainFile(file);
      if (!validation.valid) {
        setMessage({ type: 'error', text: validation.message });
        return;
      }

      // Show validation info
      if (validation.info) {
        setMessage({
          type: 'info',
          text: `Found ${validation.info.itemCount} items (${validation.info.fileSize}) from ${new Date(validation.info.exportDate).toLocaleString()}. Importing...`,
        });
      }

      // Import file
      const result = await importBrainFile(file);
      if (result.success) {
        setMessage({ type: 'success', text: result.message });
        setTimeout(() => window.location.reload(), 2000);
      } else {
        setMessage({ type: 'error', text: result.message });
      }
    } catch (error) {
      setMessage({ type: 'error', text: `Import failed: ${error}` });
    } finally {
      setIsImporting(false);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    }
  };

  // Auto-save handlers
  const handleSetupAutoSave = async () => {
    try {
      const dirHandle = await requestAutoSaveDirectory();
      setAutoSaveDirectory(dirHandle);

      // Enable auto-save with directory handle
      await autoSaveManager.enableLocal(dirHandle);

      await loadAllData();
      setMessage({ type: 'success', text: 'Auto-save enabled! Your data will be automatically saved to the selected folder.' });
    } catch (error) {
      setMessage({ type: 'error', text: `${error}` });
    }
  };

  const handleAutoSaveNow = async () => {
    if (!autoSaveDirectory) {
      setMessage({ type: 'error', text: 'Please configure auto-save directory first' });
      return;
    }

    try {
      setMessage({ type: 'info', text: 'Saving...' });
      const result = await autoSave(autoSaveDirectory);

      await addHistoryEntry({
        filename: result.filename,
        size: result.size,
        compressed: result.compressed,
        type: 'auto',
        destination: 'local',
        status: 'success',
      });

      await loadAllData();
      setMessage({ type: 'success', text: `Auto-saved: ${result.filename} (${formatFileSize(result.size)})` });
    } catch (error) {
      setMessage({ type: 'error', text: `Auto-save failed: ${error}` });
    }
  };

  // Calendar Import/Export handlers
  const handleExportCalendar = async () => {
    try {
      setIsExportingCalendar(true);
      setMessage(null);

      const result = exportToICS(events);

      if (!result.success || !result.data) {
        setMessage({ type: 'error', text: result.error || 'Export failed' });
        return;
      }

      downloadICS(result.data, `calendar-${format(new Date(), 'yyyy-MM-dd')}.ics`);

      const eventCount = Object.values(events).reduce((acc, arr) => acc + arr.length, 0);
      setMessage({
        type: 'success',
        text: `Calendar exported successfully! ${eventCount} events saved to .ics file.`
      });
    } catch (error) {
      setMessage({ type: 'error', text: `Calendar export failed: ${error}` });
    } finally {
      setIsExportingCalendar(false);
    }
  };

  const handleImportCalendarClick = () => {
    icsFileInputRef.current?.click();
  };

  const handleICSFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    try {
      setIsImportingCalendar(true);
      setMessage(null);

      const icsData = await readICSFile(file);
      const result = importFromICS(icsData);

      if (!result.success || !result.events) {
        setMessage({ type: 'error', text: result.error || 'Import failed' });
        return;
      }

      // Add all imported events to the calendar store
      result.events.forEach((event) => {
        // Determine dateKey from event ID or use today
        const dateKey = format(new Date(), 'yyyy-MM-dd');
        addEvent(dateKey, event.title, event.description, event);
      });

      setMessage({
        type: 'success',
        text: `Calendar imported successfully! ${result.events.length} events added.`
      });
    } catch (error) {
      setMessage({ type: 'error', text: `Calendar import failed: ${error}` });
    } finally {
      setIsImportingCalendar(false);
      if (icsFileInputRef.current) {
        icsFileInputRef.current.value = '';
      }
    }
  };

  // Preferences handlers
  const toggleCompression = async () => {
    if (!preferences) return;
    const newValue = !preferences.compressionEnabled;
    await savePreferences({ compressionEnabled: newValue });
    await loadAllData();
    setMessage({ type: 'info', text: `Compression ${newValue ? 'enabled' : 'disabled'}` });

    // Show visual feedback
    setRecentlySaved('compression');
    setTimeout(() => setRecentlySaved(null), 2000);
  };

  const toggleReminder = async () => {
    if (!preferences) return;
    const newValue = !preferences.reminderEnabled;
    await savePreferences({ reminderEnabled: newValue });
    await loadAllData();
    setMessage({ type: 'info', text: `Backup reminders ${newValue ? 'enabled' : 'disabled'}` });

    // Show visual feedback
    setRecentlySaved('reminder');
    setTimeout(() => setRecentlySaved(null), 2000);
  };

  const toggleAutoSave = async () => {
    if (!preferences) return;

    if (preferences.autoSaveEnabled) {
      // Disable auto-save
      await autoSaveManager.disableLocal();
      setAutoSaveDirectory(null);
      await loadAllData();
      setMessage({ type: 'info', text: 'Auto-save disabled' });

      // Show visual feedback
      setRecentlySaved('autoSave');
      setTimeout(() => setRecentlySaved(null), 2000);
    } else {
      // Enable auto-save - request directory
      await handleSetupAutoSave();
    }
  };

  const handleSaveCustomization = async () => {
    if (!preferences) return;

    // Validate inputs
    if (!customFilename.trim()) {
      setMessage({ type: 'error', text: 'Filename cannot be empty' });
      return;
    }

    if (versionCount < 1 || versionCount > 100) {
      setMessage({ type: 'error', text: 'Version count must be between 1 and 100' });
      return;
    }

    try {
      // Always append .brain extension
      const filenameWithExtension = `${customFilename.trim()}.brain`;

      await savePreferences({
        customFilename: filenameWithExtension,
        versionCount: versionCount,
      });

      await loadAllData();
      setMessage({ type: 'success', text: 'Auto-save preferences updated!' });
    } catch (error) {
      setMessage({ type: 'error', text: `Failed to save preferences: ${error}` });
    }
  };

  // AI Terminal handlers (legacy - now using ProviderSettings component)
  // Commented out to avoid unused variable errors
  // const handleSaveApiKey = () => {
  //   if (!tempApiKey.trim()) {
  //     setMessage({ type: 'error', text: 'API key cannot be empty' });
  //     return;
  //   }
  //   setApiKey(tempApiKey.trim());
  //   setMessage({ type: 'success', text: 'API key saved! You can now use the AI Terminal.' });
  // };
  // const handleRemoveApiKey = () => {
  //   setApiKey(null);
  //   setTempApiKey('');
  //   setMessage({ type: 'info', text: 'API key removed' });
  // };

  if (!preferences) {
    return <div className="p-6">Loading...</div>;
  }

  return (
    <div className="settings-page">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
          Settings
        </h1>
        <p className="text-base text-text-light-secondary dark:text-text-dark-secondary">
          Manage your data, backups, and preferences
        </p>
      </div>

      {/* Backup Reminder Banner */}
      {backupReminder?.show && (
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className="mb-6 p-4 rounded-lg bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark border border-status-warning-border dark:border-status-warning-border-dark flex items-start gap-3"
        >
          <span className="text-2xl">⚠️</span>
          <div className="flex-1">
            <p className="font-semibold">{backupReminder.message}</p>
            <button
              onClick={() => handleExport(preferences.compressionEnabled)}
              className="mt-2 text-sm underline hover:no-underline"
            >
              Create Backup Now
            </button>
          </div>
        </motion.div>
      )}

      {/* Message Banner */}
      <AnimatePresence>
        {message && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
            className={`mb-6 p-4 rounded-lg ${
              message.type === 'success'
                ? 'bg-status-success-bg dark:bg-status-success-bg-dark text-status-success-text dark:text-status-success-text-dark border border-status-success-border dark:border-status-success-border-dark'
                : message.type === 'error'
                ? 'bg-status-error-bg dark:bg-status-error-bg-dark text-status-error-text dark:text-status-error-text-dark border border-status-error-border dark:border-status-error-border-dark'
                : message.type === 'warning'
                ? 'bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark border border-status-warning-border dark:border-status-warning-border-dark'
                : 'bg-status-info-bg dark:bg-status-info-bg-dark text-status-info-text dark:text-status-info-text-dark border border-status-info-border dark:border-status-info-border-dark'
            }`}
          >
            {message.text}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Privacy-First Local Storage Notice */}
      <div className="mb-6 p-4 rounded-lg bg-status-success-bg dark:bg-status-success-bg-dark border border-status-success-border dark:border-status-success-border-dark">
        <p className="text-sm text-status-success-text dark:text-status-success-text-dark">
          <strong>🔒 100% Private:</strong> All data stored locally in your browser using IndexedDB (50GB+ capacity).
          No cloud dependencies, no tracking, no third-party services.
        </p>
      </div>

      {/* New Browser Warning */}
