                      <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                        Number of timestamped backups to keep in the hidden .neuman-backups folder (1-100)
                      </p>
                    </div>

                    {/* Save Button */}
                    <button
                      onClick={handleSaveCustomization}
                      className="w-full px-4 py-2 bg-accent-magenta hover:bg-accent-magenta-hover text-white rounded-lg font-medium shadow-soft hover:shadow-medium transition-all duration-200"
                    >
                      💾 Save Preferences
                    </button>
                  </div>

                  {/* Manual Save Now Button */}
                  {preferences.autoSaveEnabled && (
                    <button
                      onClick={handleAutoSaveNow}
                      className="w-full px-4 py-3 bg-accent-cyan hover:bg-accent-cyan-hover text-white rounded-lg font-medium shadow-soft hover:shadow-medium transition-all duration-200"
                    >
                      💾 Save Now (Manual Trigger)
                    </button>
                  )}
                </div>
              )}
            </div>

            {/* Backup & Sync Settings (New UI) */}
            <div className="bento-card p-6">
              <BackupSettings />
            </div>

            {/* Calendar Import/Export */}
            <div className="bento-card p-6">
              <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
                📅 Calendar Import/Export
              </h2>
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-6">
                Import events from Google Calendar or export your events to .ics format for use in other calendar applications.
              </p>

              <div className="space-y-3">
                {/* Export Calendar */}
                <button
                  onClick={handleExportCalendar}
                  disabled={isExportingCalendar}
                  className="w-full px-4 py-3 bg-accent-magenta hover:bg-accent-magenta-hover disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-lg font-medium shadow-soft hover:shadow-medium transition-all duration-200"
                >
                  {isExportingCalendar ? '⏳ Exporting...' : '📤 Export Calendar (.ics)'}
                </button>

                {/* Import Calendar */}
                <button
                  onClick={handleImportCalendarClick}
                  disabled={isImportingCalendar}
                  className="w-full px-4 py-3 bg-accent-cyan hover:bg-accent-cyan-hover disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-lg font-medium shadow-soft hover:shadow-medium transition-all duration-200"
                >
                  {isImportingCalendar ? '⏳ Importing...' : '📥 Import Calendar (.ics)'}
                </button>

                {/* Hidden file input */}
                <input
                  ref={icsFileInputRef}
                  type="file"
                  accept=".ics,.ical"
                  onChange={handleICSFileSelect}
                  className="hidden"
                />
              </div>

              <div className="mt-4 p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg">
                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                  <strong>Note:</strong> .ics files are compatible with Google Calendar, Apple Calendar, Outlook, and most calendar applications.
                  Recurring events and event details are preserved during import/export.
                </p>
              </div>
            </div>

            {/* Advanced Details */}
            <div className="bento-card p-6">
              <button
                onClick={() => setShowAdvancedDetails(!showAdvancedDetails)}
                className="w-full flex items-center justify-between text-left hover:opacity-80 transition-opacity"
              >
                <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
                  Advanced Details
                </h2>
                <span className="text-2xl text-text-light-secondary dark:text-text-dark-secondary">
                  {showAdvancedDetails ? '▼' : '▶'}
                </span>
              </button>

              {showAdvancedDetails && (
                <motion.div
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: 'auto' }}
                  exit={{ opacity: 0, height: 0 }}
                  className="mt-6 space-y-6"
                >
                  {/* Storage Usage */}
                  <div>
                    <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                      IndexedDB Storage
                    </h3>
                    {storageInfo ? (
                      <div className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg space-y-2">
                        <div className="flex justify-between text-sm">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">Used:</span>
                          <span className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                            {storageInfo.usageFormatted}
                          </span>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">Available:</span>
                          <span className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                            {storageInfo.availableFormatted}
                          </span>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">Total Quota:</span>
                          <span className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                            {storageInfo.quotaFormatted}
                          </span>
                        </div>

                        {/* Progress Bar */}
                        <div className="mt-3">
                          <div className="w-full bg-neutral-300 dark:bg-neutral-700 rounded-full h-3 overflow-hidden">
                            <div
                              className={`h-3 rounded-full transition-all duration-300 ${
                                storageInfo.percentUsed > 80 ? 'bg-status-error' :
                                storageInfo.percentUsed > 60 ? 'bg-status-warning' :
                                'bg-status-success'
                              }`}
                              style={{ width: `${Math.min(storageInfo.percentUsed, 100)}%` }}
                            />
                          </div>
                          <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                            {storageInfo.percentUsed.toFixed(1)}% used
                            {storageInfo.percentUsed > 80 && (
                              <span className="text-status-error-text dark:text-status-error-text-dark ml-2">
                                ⚠️ Running low on space
                              </span>
                            )}
                          </p>
                        </div>
                      </div>
                    ) : (
                      <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                        Loading storage info...
                      </p>
                    )}
                  </div>

                  {/* Last Backup Info */}
                  <div>
                    <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                      Last Backup
                    </h3>
                    {backupHistory.length > 0 ? (
                      <div className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg space-y-2">
                        <div className="flex justify-between text-sm">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">Time:</span>
                          <span className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                            {new Date(backupHistory[0].timestamp).toLocaleString()}
                          </span>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">Size:</span>
                          <span className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                            {formatFileSize(backupHistory[0].size)}
                          </span>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">Status:</span>
                          <span className={`font-semibold ${
                            backupHistory[0].status === 'success'
                              ? 'text-status-success-text dark:text-status-success-text-dark'
                              : 'text-status-error-text dark:text-status-error-text-dark'
                          }`}>
                            {backupHistory[0].status === 'success' ? '✅ Success' : '❌ Failed'}
                          </span>
                        </div>
                        {backupHistory[0].compressed && (
                          <div className="flex justify-between text-sm">
                            <span className="text-text-light-secondary dark:text-text-dark-secondary">Compressed:</span>
                            <span className="font-semibold text-status-success-text dark:text-status-success-text-dark">
                              ✅ Yes (~70% smaller)
                            </span>
                          </div>
                        )}
                      </div>
                    ) : (
                      <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg">
                        No backups yet. Create your first backup above!
                      </p>
                    )}
                  </div>

                  {/* Browser Info */}
                  <div>
                    <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                      Browser & Capabilities
                    </h3>
                    <div className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg space-y-2">
                      <div className="flex justify-between text-sm">
                        <span className="text-text-light-secondary dark:text-text-dark-secondary">Browser:</span>
                        <span className="font-mono text-xs text-text-light-primary dark:text-text-dark-primary">
                          {navigator.userAgent.match(/(?:Firefox|Chrome|Safari|Edge)\/[\d.]+/)?.[0] || 'Unknown'}
                        </span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-text-light-secondary dark:text-text-dark-secondary">IndexedDB:</span>
                        <span className="font-semibold text-status-success-text dark:text-status-success-text-dark">
                          ✅ Supported
                        </span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-text-light-secondary dark:text-text-dark-secondary">File System Access API:</span>
                        <span className={`font-semibold ${
                          isFileSystemAccessSupported()
                            ? 'text-status-success-text dark:text-status-success-text-dark'
                            : 'text-status-warning-text dark:text-status-warning-text-dark'
                        }`}>
                          {isFileSystemAccessSupported() ? '✅ Supported' : '⚠️ Not Supported'}
                        </span>
                      </div>
                      {!isFileSystemAccessSupported() && (
                        <p className="text-xs text-status-warning-text dark:text-status-warning-text-dark mt-2 p-2 bg-status-warning-bg dark:bg-status-warning-bg-dark rounded">
                          Auto-save to folder requires a Chromium-based browser (Chrome, Edge, Brave, Arc, Opera, etc.). Manual export/import still works!
                        </p>
                      )}
                    </div>
                  </div>
                </motion.div>
              )}
            </div>

            {/* Privacy Policy Link */}
            <div className="mt-8 pt-6 border-t border-border-light dark:border-border-dark">
              <div className="text-center">
                <a
                  href="/privacy"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-2 text-sm text-accent-blue hover:text-accent-blue-hover hover:underline transition-colors"
                >
                  <span>🔒</span>
                  <span>Privacy Policy & Analytics Disclosure</span>
                </a>
                <p className="mt-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
                  Learn how we protect your privacy and what analytics we collect
                </p>
              </div>
            </div>
      </div>
    </div>
  );
};

