/**
 * Task Summary Widget
 *
 * Shows overview of tasks: due today, in progress, completed
 */

import React from 'react';
import { BaseWidget } from './BaseWidget';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useNavigate } from 'react-router-dom';

export const TaskSummaryWidget: React.FC = () => {
  const { tasks } = useKanbanStore();
  const navigate = useNavigate();

  const dueToday = tasks.filter((t) => {
    if (!t.dueDate) return false;
    const due = new Date(t.dueDate);
    const today = new Date();
    return due.toDateString() === today.toDateString();
  });

  const inProgress = tasks.filter((t) => t.status === 'inprogress');
  const completed = tasks.filter((t) => t.status === 'done');

  return (
    <BaseWidget title="Tasks" icon="✅">
      <div className="space-y-4">
        <div className="grid grid-cols-3 gap-4">
          <div>
            <div className="text-3xl font-bold text-status-warning">{dueToday.length}</div>
            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">Due Today</div>
          </div>
          <div>
            <div className="text-3xl font-bold text-accent-blue">{inProgress.length}</div>
            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">In Progress</div>
          </div>
          <div>
            <div className="text-3xl font-bold text-status-success">{completed.length}</div>
            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">Completed</div>
          </div>
        </div>
        <button
          onClick={() => navigate('/tasks')}
          className="w-full px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-lg transition-colors text-sm"
        >
          View All Tasks →
        </button>
      </div>
    </BaseWidget>
  );
};

/**
 * Upcoming Events Widget
 *
 * Shows next 3 upcoming calendar events
 */

import React from 'react';
import { BaseWidget } from './BaseWidget';
import { useCalendarStore } from '../../stores/useCalendarStore';
import { useNavigate } from 'react-router-dom';

export const UpcomingEventsWidget: React.FC = () => {
  const { events } = useCalendarStore();
  const navigate = useNavigate();

  const upcomingEvents = Object.entries(events)
    .flatMap(([dateKey, eventList]) =>
      eventList.map((event) => ({ ...event, date: dateKey }))
    )
    .filter((event) => new Date(event.date) >= new Date())
    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
    .slice(0, 3);

  return (
    <BaseWidget title="Upcoming Events" icon="📅">
      <div className="space-y-4">
        {upcomingEvents.length > 0 ? (
          <div className="space-y-3">
            {upcomingEvents.map((event) => (
              <div key={event.id} className="flex items-start gap-3 p-2 rounded hover:bg-surface-light dark:hover:bg-surface-dark transition-colors">
                <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary w-20 flex-shrink-0">
                  {new Date(event.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-medium text-text-light-primary dark:text-text-dark-primary">{event.title}</div>
                  {event.startTime && (
                    <div className="text-sm text-accent-blue dark:text-accent-blue-hover">{event.startTime}</div>
                  )}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <p className="text-text-light-secondary dark:text-text-dark-secondary">No upcoming events</p>
        )}
        <button
          onClick={() => navigate('/planning')}
          className="w-full px-4 py-2 bg-accent-magenta hover:bg-accent-magenta-hover text-white rounded-lg transition-colors text-sm"
        >
          View Calendar →
        </button>
      </div>
    </BaseWidget>
  );
};

