     1→/**
     2→ * Base Widget Component
     3→ *
     4→ * Reusable wrapper for all dashboard widgets
     5→ * Provides loading, error states, refresh button, and consistent styling
     6→ */
     7→
     8→import React, { useState, useCallback } from 'react';
     9→import { motion } from 'framer-motion';
    10→
    11→export interface BaseWidgetProps {
    12→  title: string;
    13→  icon: string;
    14→  children: React.ReactNode;
    15→  loading?: boolean;
    16→  error?: string | null;
    17→  onRefresh?: () => void;
    18→  onSettings?: () => void;
    19→  className?: string;
    20→}
    21→
    22→export const BaseWidget: React.FC<BaseWidgetProps> = ({
    23→  title,
    24→  icon,
    25→  children,
    26→  loading = false,
    27→  error = null,
    28→  onRefresh,
    29→  onSettings,
    30→  className = '',
    31→}) => {
    32→  const [isRefreshing, setIsRefreshing] = useState(false);
    33→
    34→  const handleRefresh = useCallback(async () => {
    35→    if (!onRefresh || isRefreshing) return;
    36→
    37→    setIsRefreshing(true);
    38→    try {
    39→      await onRefresh();
    40→    } finally {
    41→      // Minimum 500ms for visual feedback
    42→      setTimeout(() => setIsRefreshing(false), 500);
    43→    }
    44→  }, [onRefresh, isRefreshing]);
    45→
    46→  return (
    47→    <motion.div
    48→      initial={{ opacity: 0, y: 20 }}
    49→      animate={{ opacity: 1, y: 0 }}
    50→      transition={{ duration: 0.3 }}
    51→      className={`bg-surface-light dark:bg-surface-dark-elevated rounded-lg shadow-card p-4 flex flex-col ${className}`}
    52→    >
    53→      {/* Header */}
    54→      <div className="flex items-center justify-between mb-3">
    55→        <div className="flex items-center gap-2">
    56→          <span className="text-2xl">{icon}</span>
    57→          <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
    58→            {title}
    59→          </h3>
