   190→    return Object.values(notesObj).filter(note => note.folderId === folderId).length;
   191→  };
   192→
   193→  // Handle folder deletion
   194→  const handleDeleteFolder = (folderId: string, folderName: string) => {
   195→    setSelectedFolderId(folderId);
   196→    setSelectedFolderName(folderName);
   197→    setDeleteDialogOpen(true);
   198→  };
   199→
   200→  const confirmDeleteFolder = () => {
   201→    if (!selectedFolderId) return;
   202→
   203→    // Save folder and notes for undo
   204→    const folderToDelete = foldersObj[selectedFolderId];
   205→    if (!folderToDelete) {
