   276→        <button
   277→          onClick={() => createFolder()}
   278→          className="text-xs px-3 h-8 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors duration-150 font-medium"
   279→          title="New Folder"
   280→        >
   281→          + Folder
   282→        </button>
   283→      </div>
   284→
   285→      {/* Search Input */}
   286→      <div className="px-3 py-2">
   287→        <input
   288→          type="text"
   289→          placeholder="Search notes... (Cmd+K)"
   290→          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg
   291→                     bg-surface-light dark:bg-surface-dark
   292→                     text-text-light-primary dark:text-text-dark-primary
   293→                     placeholder-text-light-secondary dark:placeholder-text-dark-secondary
   294→                     focus:outline-none focus:ring-2 focus:ring-accent-blue transition-all"
   295→          value={searchQuery}
   296→          onChange={(e) => setSearchQuery(e.target.value)}
   297→          ref={searchInputRef}
   298→        />
   299→      </div>
   300→
   301→      {/* All Notes (root level) */}
   302→      {!searchQuery.trim() && (
   303→        <button
   304→          onClick={() => setActiveFolder(null)}
   305→          className={`w-full text-left px-3 h-8 rounded-lg transition-colors mb-1 flex-shrink-0 flex items-center text-base ${
   306→            activeFolderId === null
   307→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary font-medium'
   308→              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary'
   309→          }`}
   310→        >
   311→          📂 All Notes
   312→        </button>
   313→      )}
   314→
   315→      {/* Search Results OR Folder list */}
   316→      {searchQuery.trim() ? (
   317→        /* Search Results */
   318→        <div className="px-3 overflow-y-auto flex-1">
   319→          <h3 className="text-sm font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2">
   320→            {searchNotes(searchQuery).length} results for "{searchQuery}"
   321→          </h3>
   322→          <div className="space-y-2">
   323→            {searchNotes(searchQuery).map((note) => (
   324→              <div
   325→                key={note.id}
   326→                onClick={() => {
   327→                  setSearchQuery(''); // Clear search
   328→                  // Note will be selected via the NotesList component
   329→                }}
   330→                className="p-3 rounded-lg cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   331→              >
   332→                <div className="font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   333→                  {note.title || 'Untitled'}
   334→                </div>
   335→                <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary line-clamp-2">
   336→                  {note.contentText?.slice(0, 150)}...
   337→                </div>
   338→                <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   339→                  {new Date(note.updatedAt).toLocaleDateString()}
   340→                </div>
   341→              </div>
   342→            ))}
   343→            {searchNotes(searchQuery).length === 0 && (
   344→              <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-8">
   345→                No notes found for "{searchQuery}"
   346→              </div>
   347→            )}
   348→          </div>
   349→        </div>
   350→      ) : (
   351→        /* Folder tree - Scrollable */
   352→        <div className="space-y-1 overflow-y-auto flex-1">
   353→          {folderTree.map((node) => (
   354→            <FolderTreeNode
   355→              key={node.id}
   356→              node={node}
   357→              depth={0}
   358→              activeFolderId={activeFolderId}
   359→              expandedFolderIds={expandedFolderIds}
   360→              onSelect={setActiveFolder}
   361→              onToggleExpanded={toggleExpanded}
   362→              onDelete={handleDeleteFolder}
   363→              onRename={handleRenameFolder}
   364→              getFolderNoteCount={getFolderNoteCount}
   365→            />
   366→          ))}
   367→
   368→          {/* Empty state */}
   369→          {folderTree.length === 0 && (
   370→            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-4">
   371→              No folders yet
   372→            </div>
   373→          )}
   374→        </div>
   375→      )}
   376→
   377→      {/* Delete Folder Confirmation Dialog */}
   378→      <ConfirmDialog
   379→        isOpen={deleteDialogOpen}
   380→        onClose={() => setDeleteDialogOpen(false)}
   381→        onConfirm={confirmDeleteFolder}
   382→        title="Delete Folder"
   383→        message={`Delete folder "${selectedFolderName}"? This will also delete ${selectedFolderId ? getFolderNoteCount(selectedFolderId) : 0} note(s) inside.`}
   384→        confirmText="Delete"
   385→        variant="danger"
   386→      />
   387→
   388→      {/* Rename Folder Prompt Dialog */}
   389→      <PromptDialog
   390→        isOpen={renameDialogOpen}
   391→        onClose={() => setRenameDialogOpen(false)}
   392→        onConfirm={confirmRenameFolder}
   393→        title="Rename Folder"
   394→        message="Enter a new name for this folder:"
   395→        defaultValue={selectedFolderName}
   396→        placeholder="Folder name"
   397→        confirmText="Rename"
   398→      />
   399→    </div>
   400→  );
   401→};
   402→
   403→/**
   404→ * Note List Item Component
   405→ */
   406→const NoteListItem: React.FC<{ note: Note; isActive: boolean }> = ({
   407→  note,
   408→  isActive,
   409→}) => {
   410→  const setActiveNote = useNotesStore((state) => state.setActiveNote);
   411→  const deleteNote = useNotesStore((state) => state.deleteNote);
   412→  const togglePin = useNotesStore((state) => state.togglePin);
   413→  const toggleFavorite = useNotesStore((state) => state.toggleFavorite);
   414→  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
   415→  const [isExporting, setIsExporting] = useState(false);
   416→  const [exportSuccess, setExportSuccess] = useState<string | null>(null);
   417→
   418→  // Handle PDF export with loading state
   419→  const handlePDFExport = async (e: React.MouseEvent) => {
   420→    e.stopPropagation();
   421→    setIsExporting(true);
   422→    try {
   423→      await exportNoteToPDF(note, (filename) => {
   424→        setExportSuccess(filename);
   425→        setTimeout(() => setExportSuccess(null), 3000); // Clear after 3s
   426→      });
   427→    } catch (error) {
   428→      console.error('Export failed:', error);
   429→    } finally {
   430→      setIsExporting(false);
   431→    }
   432→  };
   433→
   434→  // Format date
   435→  const formatDate = (date: Date) => {
   436→    const now = new Date();
   437→    const diff = now.getTime() - new Date(date).getTime();
   438→    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   439→
   440→    if (days === 0) return 'Today';
   441→    if (days === 1) return 'Yesterday';
   442→    if (days < 7) return `${days} days ago`;
   443→    return new Date(date).toLocaleDateString();
   444→  };
   445→
   446→  // First line of content
   447→  const preview = note.contentText.split('\n')[0] || 'No content';
   448→
   449→  return (
   450→    <div
   451→      className={`group relative p-3 rounded-lg cursor-pointer transition-all ${
   452→        isActive
   453→          ? 'bg-primary-cyan bg-opacity-10 border-l-4 border-primary-cyan'
   454→          : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated border-l-4 border-transparent'
   455→      }`}
   456→      onClick={() => setActiveNote(note.id)}
   457→    >
   458→      {/* Pin/Favorite indicators */}
   459→      <div className="absolute top-2 right-2 flex gap-1">
   460→        {note.isFavorite && <div className="text-amber-500">⭐</div>}
   461→        {note.isPinned && <div className="text-amber-500">📌</div>}
   462→      </div>
   463→
   464→      {/* Title */}
   465→      <h4 className="font-medium text-text-light-primary dark:text-text-dark-primary mb-1 pr-6 truncate">
   466→        {note.title}
   467→      </h4>
   468→
   469→      {/* Preview */}
   470→      <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary line-clamp-2 mb-2">
   471→        {preview}
   472→      </p>
   473→
   474→      {/* Meta */}
   475→      <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
   476→        <span>{formatDate(note.updatedAt)}</span>
   477→        {note.tags.length > 0 && (
   478→          <span className="truncate ml-2">🏷️ {note.tags[0]}</span>
   479→        )}
   480→      </div>
   481→
   482→      {/* Export Success Notification */}
   483→      {exportSuccess && (
   484→        <div className="absolute -top-8 left-0 right-0 bg-green-500 text-white text-xs py-1 px-2 rounded shadow-lg z-10 text-center">
   485→          ✓ Exported: {exportSuccess}
   486→        </div>
   487→      )}
   488→
   489→      {/* Actions (show on hover) */}
   490→      <div className="absolute top-2 right-8 opacity-0 group-hover:opacity-100 transition-opacity flex gap-1">
   491→        <button
   492→          onClick={(e) => {
   493→            e.stopPropagation();
   494→            exportNoteToMarkdown(note);
   495→          }}
   496→          className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded"
   497→          title="Export to Markdown"
   498→        >
   499→          ⬇️
   500→        </button>
   501→        <button
   502→          onClick={handlePDFExport}
   503→          disabled={isExporting}
   504→          className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded disabled:opacity-50 disabled:cursor-not-allowed"
   505→          title={isExporting ? 'Exporting...' : 'Export to PDF'}
   506→        >
   507→          {isExporting ? '⏳' : '📄'}
   508→        </button>
   509→        <button
   510→          onClick={(e) => {
   511→            e.stopPropagation();
   512→            toggleFavorite(note.id);
   513→          }}
   514→          className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded"
   515→          title={note.isFavorite ? 'Unfavorite' : 'Favorite'}
   516→        >
   517→          {note.isFavorite ? '⭐' : '☆'}
   518→        </button>
   519→        <button
   520→          onClick={(e) => {
   521→            e.stopPropagation();
   522→            togglePin(note.id);
   523→          }}
   524→          className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded"
   525→          title={note.isPinned ? 'Unpin' : 'Pin'}
   526→        >
   527→          📌
   528→        </button>
   529→        <button
   530→          onClick={(e) => {
   531→            e.stopPropagation();
   532→            setShowDeleteDialog(true);
   533→          }}
   534→          className="p-1 hover:bg-red-100 dark:hover:bg-red-900 rounded text-red-600"
   535→          title="Delete"
   536→        >
   537→          🗑️
   538→        </button>
   539→      </div>
   540→
   541→      {/* Delete Confirmation Dialog */}
   542→      {showDeleteDialog && (
   543→        <ConfirmDialog
   544→          isOpen={true}
   545→          onClose={() => setShowDeleteDialog(false)}
   546→          onConfirm={() => {
   547→            deleteNote(note.id);
   548→            setShowDeleteDialog(false);
   549→          }}
   550→          title="Delete Note"
   551→          message={`Are you sure you want to delete "${note.title}"? This action cannot be undone.`}
   552→          variant="danger"
   553→        />
   554→      )}
   555→    </div>
   556→  );
   557→};
   558→
   559→/**
   560→ * Notes List Component
   561→ */
   562→const NotesList: React.FC = () => {
   563→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   564→  // Get raw notes and store config (stable references)
   565→  const notesObj = useNotesStore((state) => state.notes);
   566→  const sortConfig = useNotesStore((state) => state.sortConfig);
   567→  const filter = useNotesStore((state) => state.filter);
   568→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   569→  const createNote = useNotesStore((state) => state.createNote);
   570→
   571→  // Compute filtered/sorted notes with useMemo
   572→  const notes = useMemo(() => {
   573→    // Filter by folder
   574→    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
   575→    let filtered = activeFolderId === null
   576→      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
   577→      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);
   578→
   579→    // Apply filter (archived, pinned, favorites, etc.)
   580→    switch (filter) {
   581→      case 'favorites':
   582→        filtered = filtered.filter((note) => note.isFavorite);
   583→        break;
   584→      case 'pinned':
   585→        filtered = filtered.filter((note) => note.isPinned);
   586→        break;
   587→      case 'archived':
   588→        filtered = filtered.filter((note) => note.isArchived);
   589→        break;
   590→      case 'unarchived':
   591→        filtered = filtered.filter((note) => !note.isArchived);
   592→        break;
   593→    }
   594→
   595→    // Sort notes
   596→    const sorted = [...filtered].sort((a, b) => {
   597→      let comparison = 0;
   598→      switch (sortConfig.field) {
   599→        case 'title':
   600→          comparison = a.title.localeCompare(b.title);
   601→          break;
   602→        case 'createdAt':
   603→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
   604→          break;
   605→        case 'updatedAt':
   606→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   607→          break;
   608→      }
   609→      return sortConfig.order === 'asc' ? comparison : -comparison;
   610→    });
   611→
   612→    // Always pin pinned notes to top
   613→    return sorted.sort((a, b) => {
   614→      if (a.isPinned && !b.isPinned) return -1;
   615→      if (!a.isPinned && b.isPinned) return 1;
   616→      return 0;
   617→    });
   618→  }, [notesObj, activeFolderId, sortConfig, filter]);
   619→
   620→  return (
   621→    <div className="flex-1 overflow-y-auto">
   622→      <div className="bento-card p-4 m-3">
   623→        {/* Notes header */}
   624→        <div className="flex items-center justify-between mb-4">
   625→          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   626→            Notes ({notes.length})
   627→          </h3>
   628→          <button
   629→            onClick={() => createNote({ folderId: activeFolderId })}
   630→            className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
   631→          >
   632→            + New Note
   633→          </button>
   634→        </div>
   635→
   636→      {/* Notes list */}
   637→      <div className="space-y-2">
   638→        {notes.map((note) => (
   639→          <NoteListItem
   640→            key={note.id}
   641→            note={note}
   642→            isActive={note.id === activeNoteId}
   643→          />
   644→        ))}
   645→      </div>
   646→
   647→      {/* Empty state */}
   648→      {notes.length === 0 && (
   649→        <div className="text-center py-12">
   650→          <div className="text-6xl mb-4">📝</div>
   651→          <h3 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   652→            No notes yet
   653→          </h3>
   654→          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-4">
   655→            Create your first note to get started
   656→          </p>
   657→          <button
   658→            onClick={() => createNote({ folderId: activeFolderId })}
   659→            className="px-4 py-2 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 font-medium"
   660→          >
   661→            Create Note
   662→          </button>
   663→        </div>
   664→      )}
   665→      </div>
   666→    </div>
   667→  );
   668→};
   669→
   670→/**
   671→ * Notes Page Component
   672→ */
   673→export const Notes: React.FC = () => {
   674→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   675→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
   676→
   677→  useEffect(() => {
   678→    document.title = 'Notes - Neuman Brain';
   679→    console.log('📝 Notes page loaded');
   680→  }, []);
   681→
   682→  return (
   683→    <div className="notes-page">
   684→      {/* Page Header */}
   685→      <div className="mb-8">
   686→        <h1 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   687→          Notes
   688→        </h1>
   689→        <p className="text-base text-text-light-secondary dark:text-text-dark-secondary">
   690→          Your second brain for ideas, thoughts, and knowledge
   691→        </p>
   692→      </div>
   693→
   694→      {/* Notes Content */}
   695→      <div className="h-[calc(100vh-280px)] flex gap-8 relative">
   696→        {/* Sidebar toggle button */}
   697→        <button
   698→          onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
   699→          className="absolute left-0 top-4 z-20 p-2 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-r-lg hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-all duration-200"
   700→          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
   701→          style={{ transform: isSidebarCollapsed ? 'translateX(0)' : 'translateX(0)' }}
   702→        >
   703→          {isSidebarCollapsed ? '→' : '←'}
   704→        </button>
   705→
   706→        {/* Left Sidebar - Folders + Notes List */}
   707→        <AnimatePresence>
   708→        {!isSidebarCollapsed && (
   709→          <motion.div
   710→            initial={{ width: 0, opacity: 0 }}
   711→            animate={{ width: 320, opacity: 1 }}
   712→            exit={{ width: 0, opacity: 0 }}
   713→            transition={{ duration: 0.2 }}
   714→            className="flex-shrink-0 border-r border-border-light dark:border-border-dark bg-transparent flex flex-col overflow-hidden"
   715→          >
   716→            <FolderSidebar />
   717→            <NotesList />
   718→          </motion.div>
   719→        )}
   720→      </AnimatePresence>
   721→
   722→      {/* Center - Editor */}
   723→      <div className="flex-1 overflow-hidden">
   724→        <div className="h-full overflow-hidden border border-border-light dark:border-border-dark rounded-lg">
   725→          {activeNoteId ? (
   726→            <NotesEditor noteId={activeNoteId} />
   727→          ) : (
   728→            <NotesEditorEmpty />
   729→          )}
   730→        </div>
   731→      </div>
   732→
   733→      {/* Right Sidebar - Metadata (Future) */}
   734→      {/* TODO: Add note metadata panel */}
   735→    </div>
   736→    </div>
   737→  );
   738→};
