      <div className="mb-8">
        <h1 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
          Notes
        </h1>
        <p className="text-base text-text-light-secondary dark:text-text-dark-secondary">
          Your second brain for ideas, thoughts, and knowledge
        </p>
      </div>

      {/* Notes Content */}
      <div className="h-[calc(100vh-280px)] flex gap-8 relative">
        {/* Sidebar toggle button */}
        <button
          onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
          className="absolute left-0 top-4 z-20 p-2 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-r-lg hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-all duration-200"
          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
          style={{ transform: isSidebarCollapsed ? 'translateX(0)' : 'translateX(0)' }}
        >
          {isSidebarCollapsed ? '→' : '←'}
        </button>

        {/* Left Sidebar - Folders + Notes List */}
        <AnimatePresence>
        {!isSidebarCollapsed && (
          <motion.div
            initial={{ width: 0, opacity: 0 }}
            animate={{ width: 320, opacity: 1 }}
            exit={{ width: 0, opacity: 0 }}
            transition={{ duration: 0.2 }}
            className="flex-shrink-0 border-r border-border-light dark:border-border-dark bg-transparent flex flex-col overflow-hidden"
          >
            <FolderSidebar />
            <NotesList />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Center - Editor */}
      <div className="flex-1 overflow-hidden">
        <div className="h-full overflow-hidden border border-border-light dark:border-border-dark rounded-lg">
          {activeNoteId ? (
            <NotesEditor noteId={activeNoteId} />
          ) : (
            <NotesEditorEmpty />
          )}
        </div>
      </div>

      {/* Right Sidebar - Metadata (Future) */}
      {/* TODO: Add note metadata panel */}
    </div>
    </div>
  );
};

